// Join TranscriptAPI segments into one plain-text transcript and carry
// the video metadata (title/author/thumbnail) forward for the blog draft.
const data = $input.first().json;
const transcriptText = (data.transcript || []).map((s) => s.text).join(' ');
const meta = data.metadata || {};
return [
  {
    json: {
      videoId: data.video_id,
      title: meta.title || null,
      author: meta.author_name || null,
      thumbnail: meta.thumbnail_url || null,
      language: data.language || null,
      transcriptText,
    },
  },
];

