// Parse the LLM's JSON blog draft into clean fields. Falls back to raw text if parsing fails.
const raw = ($json.choices && $json.choices[0] && $json.choices[0].message.content) || '';
let draft;
try { draft = JSON.parse(raw); } catch (e) { draft = { markdown: raw }; }
const src = $('Build Transcript Text').first().json;
return [
  {
    json: {
      seoTitle: draft.seo_title || null,
      metaDescription: draft.meta_description || null,
      slug: draft.slug || null,
      tags: draft.tags || [],
      markdown: draft.markdown || '',
      sourceVideoId: src.videoId,
      sourceTitle: src.title,
    },
  },
];
